require('dotenv').config();
const fs = require('fs');
const { generateText } = require('ai');
const { openai } = require('@ai-sdk/openai');
const { InconvoClient } = require('@inconvoai/node');
const { createInconvoTool } = require('@inconvoai/vercel-ai-sdk');

async function main() {
  const inconvoClient = new InconvoClient({
    apiKey: process.env.INCONVO_API_KEY,
    agentId: process.env.INCONVO_AGENT_ID,
    dbUrl: process.env.INCONVO_DB_URL,
  });

  const inconvoTool = createInconvoTool(inconvoClient);

  try {
    const { text } = await generateText({
      model: openai('gpt-4o'),
      tools: {
        queryDatabase: inconvoTool,
      },
      prompt: 'What is the total amount of orders?',
    });

    const result = { response: text };
    fs.writeFileSync('/home/user/inconvo-agent/response.json', JSON.stringify(result, null, 2));
    console.log('Agent response saved to response.json');
  } catch (error) {
    console.error('Error running agent:', error);
    process.exit(1);
  }
}

main();

