import 'dotenv/config';
import fs from 'fs';
import { generateText } from 'ai';
import { openai } from '@ai-sdk/openai';
import { Inconvo } from '@inconvoai/node';
import { inconvoDataAgent } from '@inconvoai/vercel-ai-sdk';

async function main() {
  console.log('Starting agent...');
  const inconvoClient = new Inconvo({
    apiKey: process.env.INCONVO_API_KEY,
  });

  const tools = inconvoDataAgent({
    inconvo: inconvoClient,
    agentId: process.env.INCONVO_AGENT_ID,
    userIdentifier: 'user-123',
    userContext: { role: 'admin' }
  });

  try {
    const result = await generateText({
      model: openai('gpt-4o'),
      tools: tools,
      maxSteps: 10,
      prompt: 'What is the total amount of orders? Use the provided tools to find out. First get the summary, then start a conversation, then message the data agent.',
      onStepFinish: (step) => {
        console.log(`Step ${step.stepNumber} finished. Reason: ${step.finishReason}`);
        if (step.toolCalls) {
          console.log('Tool calls:', step.toolCalls.map(tc => tc.toolName).join(', '));
        }
        if (step.toolResults) {
          console.log('Tool results received for:', step.toolResults.map(tr => tr.toolName).join(', '));
        }
      }
    });

    const responseText = result.text;
    const output = { response: responseText };
    fs.writeFileSync('/home/user/inconvo-agent/response.json', JSON.stringify(output, null, 2));
    console.log('Agent response saved to response.json');
    console.log('Final text:', responseText);
  } catch (error) {
    console.error('Error running agent:', error);
    process.exit(1);
  }
}

main();

